VALUES
  ('medical-tech-moex-05818', 'medical-tech', 'medical-tech-moex-109-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列何種試驗可搭配公開的人類免疫缺乏病毒抗藥資料庫，同時分析第一型人類免疫缺乏病毒之基因型與抗 病毒耐藥性？', '["病毒斑點試驗", "即時聚合酶連鎖反應", "轉錄介導核酸擴增試驗", "高通量定序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:25+00:00", "source_pdf_sha1": "9d5fa0cfde76", "answer_pdf_sha1": "9f3221475c56", "source_family": "moex-gov-tw", "moex": {"exam_code": "109020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "109", "exam_name": "109年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 65, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
